import { redirect } from "next/navigation";
import Link from "next/link";
import { fetchMethods, toCSV, downloadHref } from "@/lib/api/round3";
import { requireTenantContext } from "@/lib/tenant";

export default async function MethodsPage() {
  const tenant = await requireTenantContext();
  if (!tenant) redirect("/login");

  const methods = await fetchMethods(tenant.organizationId);
  const csvData = toCSV(
    methods.map((m) => ({
      name: m.name,
      latestVersion: m.latestVersion,
      status: m.status,
      usageCount: m.usageCount,
      description: m.description,
    })),
  );

  function statusColor(status: string): string {
    switch (status) {
      case "active": return "var(--gold)";
      case "candidate": return "var(--parchment)";
      case "deprecated": return "var(--parchment-dim)";
      default: return "var(--parchment-dim)";
    }
  }

  return (
    <main style={{ maxWidth: "960px", margin: "0 auto", padding: "3rem 2rem" }}>
      <h1
        style={{
          fontFamily: "'Cinzel', serif",
          color: "var(--gold)",
          letterSpacing: "0.08em",
        }}
      >
        Methods registry
      </h1>
      <p style={{ color: "var(--parchment-dim)", marginBottom: "0.75rem", fontSize: "0.9rem" }}>
        Registered extraction and analysis methods with versioned documentation.
      </p>

      <div style={{ display: "flex", gap: "0.75rem", marginBottom: "1.5rem", flexWrap: "wrap" }}>
        <Link href="/methods/candidates" className="btn" style={{ fontSize: "0.65rem", textDecoration: "none" }}>
          View candidates
        </Link>
        <a
          href={downloadHref(csvData, "text/csv")}
          download="methods.csv"
          className="btn"
          style={{ fontSize: "0.65rem", textDecoration: "none" }}
        >
          Download CSV
        </a>
        <a
          href={downloadHref(JSON.stringify(methods, null, 2), "application/json")}
          download="methods.json"
          className="btn"
          style={{ fontSize: "0.65rem", textDecoration: "none" }}
        >
          Download JSON
        </a>
      </div>

      {methods.length === 0 ? (
        <div className="portal-card" style={{ padding: "1rem 1.25rem", color: "var(--parchment-dim)" }}>
          No methods registered yet. Methods are added when extraction pipelines are configured.
        </div>
      ) : (
        <ul style={{ listStyle: "none", padding: 0, margin: 0, display: "flex", flexDirection: "column", gap: "0.75rem" }}>
          {methods.map((m) => (
            <li key={m.name} className="portal-card" style={{ padding: "1rem 1.25rem" }}>
              <div style={{ display: "flex", justifyContent: "space-between", flexWrap: "wrap", gap: "0.5rem" }}>
                <Link
                  href={`/methods/${encodeURIComponent(m.name)}/${encodeURIComponent(m.latestVersion)}`}
                  style={{ color: "var(--gold)", textDecoration: "none", fontFamily: "'Cinzel', serif", fontSize: "0.85rem" }}
                >
                  {m.name}
                </Link>
                <span style={{ fontSize: "0.65rem", color: statusColor(m.status), textTransform: "uppercase" }}>
                  {m.status}
                </span>
              </div>
              <p style={{ marginTop: "0.35rem", color: "var(--parchment)", fontSize: "0.85rem" }}>
                {m.description}
              </p>
              <div style={{ marginTop: "0.25rem", fontSize: "0.65rem", color: "var(--parchment-dim)" }}>
                v{m.latestVersion} · {m.usageCount} uses
              </div>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}

import type { Metadata } from "next";
import Link from "next/link";
import { notFound } from "next/navigation";

import PublicHeader from "@/components/PublicHeader";
import { getCatalog, publicModesForMethod } from "@/lib/failureModes";
import { getFounder } from "@/lib/auth";

export const metadata: Metadata = {
  title: "Methodology · failure modes",
};

const SEVERITY_LABEL: Record<string, string> = {
  high: "High",
  medium: "Medium",
  low: "Low",
};

const SEVERITY_COLOR: Record<string, string> = {
  high: "var(--ember, #c0392b)",
  medium: "var(--amber, #d4a017)",
  low: "var(--public-muted, #888)",
};

/**
 * Public methodology surface for a single method, rendering the
 * curated failure-mode catalog. Only entries with `public: true`
 * appear here — the firm uses the private set as a workspace before
 * deciding what is mature enough to publish.
 */
export default async function PublicMethodologyMethodPage({
  params,
}: {
  params: Promise<{ method: string }>;
}) {
  const { method } = await params;
  const methodName = decodeURIComponent(method);
  const catalog = getCatalog(methodName);
  if (!catalog) notFound();

  const publicModes = publicModesForMethod(methodName);
  const totalCount =
    catalog.failures === "deliberately-empty" ? 0 : catalog.modes.length;
  const founder = await getFounder();

  return (
    <>
      <PublicHeader authed={Boolean(founder)} />
      <main className="public-container public-methodology-page">
        <Link href="/methodology" className="public-muted" style={{ fontSize: "0.75rem" }}>
          ← Methodology
        </Link>
        <h1 className="public-title" style={{ marginTop: "0.5rem" }}>
          Failure modes ·{" "}
          <span style={{ fontFamily: "monospace" }}>{methodName}</span>
        </h1>
        <p className="public-muted public-lede">
          Methods are not universally applicable. This page lists the ways
          this method is known or suspected to break, so a reader can judge
          whether to trust, modify, or reject it for their own use.
        </p>

        <p className="public-muted" style={{ fontSize: "0.78rem" }}>
          <Link href={`/methodology/${encodeURIComponent(methodName)}/track-record`}>
            View empirical track record →
          </Link>
        </p>

        {catalog.failures === "deliberately-empty" ? (
          <section className="public-section">
            <div className="public-card public-method-note" role="note">
              <h2>Deliberately empty</h2>
              <p>{catalog.justification}</p>
            </div>
          </section>
        ) : null}

        <section className="public-section">
          <h2>
            {publicModes.length} of {totalCount} modes published
          </h2>
          {publicModes.length === 0 ? (
            <p className="public-muted">
              The catalog for this method exists but no entries have been
              marked <span className="mono">public</span> yet. Catalogs are
              developed internally first; published entries appear here once
              the firm has thought through the framing.
            </p>
          ) : (
            <ul style={{ listStyle: "none", padding: 0, margin: 0, display: "grid", gap: "1rem" }}>
              {publicModes.map((mode) => (
                <li key={mode.name}>
                  <details
                    className="public-card public-method-card"
                    style={{ padding: "1rem 1.25rem" }}
                  >
                    <summary
                      style={{
                        cursor: "pointer",
                        display: "flex",
                        alignItems: "baseline",
                        gap: "0.75rem",
                        flexWrap: "wrap",
                        listStyle: "none",
                      }}
                    >
                      <span
                        style={{
                          padding: "0.15rem 0.5rem",
                          border: `1px solid ${SEVERITY_COLOR[mode.severity] ?? "var(--public-rule, #ccc)"}`,
                          color: SEVERITY_COLOR[mode.severity] ?? "var(--public-muted)",
                          fontFamily: "monospace",
                          fontSize: "0.65rem",
                          letterSpacing: "0.15em",
                          textTransform: "uppercase",
                        }}
                      >
                        {SEVERITY_LABEL[mode.severity] ?? mode.severity}
                      </span>
                      <h3 style={{ margin: 0, fontSize: "1rem" }}>
                        {mode.name}
                      </h3>
                    </summary>

                    <p style={{ marginTop: "0.65rem" }}>{mode.description}</p>

                    <dl
                      style={{
                        margin: "0.6rem 0 0",
                        display: "grid",
                        gridTemplateColumns: "max-content 1fr",
                        columnGap: "0.75rem",
